import{_ as e,c as a,o,ag as i}from"./chunks/framework.DD2hp6gW.js";const g=JSON.parse('{"title":"Cart & Checkout Integration","description":"","frontmatter":{},"headers":[],"relativePath":"cart-checkout.md","filePath":"cart-checkout.md","lastUpdated":1777110900000}'),r={name:"cart-checkout.md"};function s(l,t,n,d,c,h){return o(),a("div",null,t[0]||(t[0]=[i('<h1 id="cart-checkout-integration" tabindex="-1">Cart &amp; Checkout Integration <a class="header-anchor" href="#cart-checkout-integration" aria-label="Permalink to &quot;Cart &amp; Checkout Integration&quot;">​</a></h1><p>OptionBay ensures that all customer customizations follow the shopper through their entire journey — from the initial &quot;Add to Cart&quot; to the final checkout confirmation and beyond.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>When a customer selects options and clicks &quot;Add to Cart&quot;, OptionBay processes the data through a 5-stage pipeline:</p><ol><li><strong>Validation:</strong> All required fields and constraints are checked server-side.</li><li><strong>Data Storage:</strong> The selected options are attached to the cart item as session data.</li><li><strong>Price Calculation:</strong> Addon prices are calculated and added to the product&#39;s base price.</li><li><strong>Display:</strong> The selected options are shown in the cart and checkout summaries.</li><li><strong>Order Storage:</strong> On checkout, the data is permanently saved as order item meta.</li></ol><h2 id="the-cart-page" tabindex="-1">The Cart Page <a class="header-anchor" href="#the-cart-page" aria-label="Permalink to &quot;The Cart Page&quot;">​</a></h2><p>When a product with custom options is added to the cart, OptionBay attaches the selection data to the cart item.</p><h3 id="displaying-options" tabindex="-1">Displaying Options <a class="header-anchor" href="#displaying-options" aria-label="Permalink to &quot;Displaying Options&quot;">​</a></h3><p>In the standard WooCommerce cart template, the selected options appear directly below the product name as a list of key-value pairs:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Format</th><th style="text-align:left;">Example</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Text/Textarea</strong></td><td style="text-align:left;"><code>Engraving: Hello World</code></td></tr><tr><td style="text-align:left;"><strong>Select/Radio</strong></td><td style="text-align:left;"><code>Size: Large</code></td></tr><tr><td style="text-align:left;"><strong>Checkbox</strong></td><td style="text-align:left;"><code>Extras: Gift Wrap, Insurance</code></td></tr><tr><td style="text-align:left;"><strong>Color Swatch</strong></td><td style="text-align:left;"><code>Color: Midnight Blue</code></td></tr><tr><td style="text-align:left;"><strong>Image Swatch</strong></td><td style="text-align:left;"><code>Pattern: Floral Print</code></td></tr><tr><td style="text-align:left;"><strong>Single Checkbox</strong></td><td style="text-align:left;"><code>Rush Processing: Yes</code></td></tr><tr><td style="text-align:left;"><strong>File Upload</strong></td><td style="text-align:left;"><code>Logo: my-logo.png</code> (clickable link)</td></tr><tr><td style="text-align:left;"><strong>Number</strong></td><td style="text-align:left;"><code>Width (cm): 42</code></td></tr><tr><td style="text-align:left;"><strong>Email</strong></td><td style="text-align:left;"><code>Recipient: friend@example.com</code></td></tr></tbody></table><h3 id="price-adjustments" tabindex="-1">Price Adjustments <a class="header-anchor" href="#price-adjustments" aria-label="Permalink to &quot;Price Adjustments&quot;">​</a></h3><p>The product price shown in the cart reflects the <strong>total price</strong> including all selected addons:</p><ul><li>If a product is $100 and a $20 &quot;Gift Wrap&quot; addon is selected, the cart will display the item price as <strong>$120.00</strong>.</li><li>Multiple addons are cumulative. A $100 product with a $20 wrap and a $5 card shows as <strong>$125.00</strong>.</li><li>This ensures that the cart subtotal and grand total are always accurate.</li></ul><h3 id="weight-adjustments" tabindex="-1">Weight Adjustments <a class="header-anchor" href="#weight-adjustments" aria-label="Permalink to &quot;Weight Adjustments&quot;">​</a></h3><p>If you have configured <strong>Weight</strong> values for your fields or options, the total weight of the cart item is automatically updated. This is critical for stores that use weight-based shipping methods (like UPS, FedEx, or Weight-Table rate shipping).</p><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>Weight adjustments happen at the cart item level. Each addon&#39;s weight value is added to the product&#39;s base weight, and WooCommerce&#39;s shipping calculator uses the updated total weight.</p></div><h2 id="the-checkout-page" tabindex="-1">The Checkout Page <a class="header-anchor" href="#the-checkout-page" aria-label="Permalink to &quot;The Checkout Page&quot;">​</a></h2><p>On the checkout page, the selected options continue to be displayed in the <strong>&quot;Your Order&quot;</strong> review section. This gives customers one final chance to verify their customizations before completing the purchase.</p><p>The pricing shown at checkout is identical to the cart — all addon costs are included in the line item price.</p><h2 id="thank-you-page-customer-emails" tabindex="-1">Thank You Page &amp; Customer Emails <a class="header-anchor" href="#thank-you-page-customer-emails" aria-label="Permalink to &quot;Thank You Page &amp; Customer Emails&quot;">​</a></h2><p>After the order is placed:</p><ol><li><strong>Thank You Page:</strong> The customer sees their selected options in the order details table on the confirmation page.</li><li><strong>Order Confirmation Email (Customer):</strong> The customer receives an email containing the full list of custom options for each line item, so they have a personal record of their choices.</li><li><strong>New Order Email (Admin):</strong> The store administrator receives an email with all the custom option details, making it easy to begin fulfillment.</li></ol><h2 id="modifying-options" tabindex="-1">Modifying Options <a class="header-anchor" href="#modifying-options" aria-label="Permalink to &quot;Modifying Options&quot;">​</a></h2><p>Currently, to change the selected options, a customer must:</p><ol><li>Remove the item from their cart.</li><li>Return to the product page.</li><li>Re-select their options and add the product again.</li></ol><p>This ensures that all conditional logic, pricing calculations, and validation rules are properly re-evaluated.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="./order-management.html">Order Management for Admins</a></li><li><a href="./frontend-display.html">Frontend Display Details</a></li></ul>',28)]))}const u=e(r,[["render",s]]);export{g as __pageData,u as default};
